        : Promise.resolve([]),
    ]);

    if (roomInfos.length !== roomIds.length) throw new NotFoundError(ErrorCode.ROOM_NOT_FOUND);
    if (priceSettingIds.length && feeSettings.length !== priceSettingIds.length) {
      throw new NotFoundError(ErrorCode.PRICE_SETTING_NOT_FOUND);
