        stayDate: In(stayDateSet),
        ...(priceSettingIdSet.length ? { priceSettingId: In(priceSettingIdSet) } : {}),
      },
    });

    const rateCalendarMap = new Map<string, RateCalendar>();
    rateCalendars.forEach(rate => {
      const key = `${rate.roomId}-${rate.priceSettingId}-${dayjs(rate.stayDate).format('YYYY-MM-DD')}`;
      rateCalendarMap.set(key, rate);
    });

    const totalBasePrice = requestedStayDates.reduce((total, stay) => {
      const key = `${stay.roomId}-${stay.priceSettingId}-${stay.stayDate}`;
      const rate = rateCalendarMap.get(key);
      if (!rate) throw new BusinessLogicError(ErrorCode.PRICE_SETTINGS_INVALID);
      return total + Number(rate.baseRate || 0);
    }, 0);
    return totalBasePrice;
